2780 // Match the following IR pattern:
2781 //   %x.lowbits = and i8 %x, %lowbitmask
2782 //   %x.lowbits.are.zero = icmp eq i8 %x.lowbits, 0
2783 //   %x.biased = add i8 %x, %bias
2784 //   %x.biased.highbits = and i8 %x.biased, %highbitmask
2785 //   %x.roundedup = select i1 %x.lowbits.are.zero, i8 %x, i8 %x.biased.highbits
2786 // Define:
2787 //   %alignment = add i8 %lowbitmask, 1
2788 // Iff 1. an %alignment is a power-of-two (aka, %lowbitmask is a low bit mask)
2789 // and 2. %bias is equal to either %lowbitmask or %alignment,
2790 // and 3. %highbitmask is equal to ~%lowbitmask (aka, to -%alignment)
2791 // then this pattern can be transformed into:
2792 //   %x.offset = add i8 %x, %lowbitmask
2793 //   %x.roundedup = and i8 %x.offset, %highbitmask
2794 static Value *
2795 foldRoundUpIntegerWithPow2Alignment(SelectInst &SI,
2796                                     InstCombiner::BuilderTy &Builder) {
2797   Value *Cond = SI.getCondition();
2798   Value *X = SI.getTrueValue();
2799   Value *XBiasedHighBits = SI.getFalseValue();
2800 
2801   ICmpInst::Predicate Pred;
2802   Value *XLowBits;
2803   if (!match(Cond, m_ICmp(Pred, m_Value(XLowBits), m_ZeroInt())) ||
2804       !ICmpInst::isEquality(Pred))
2805     return nullptr;
2806 
2807   if (Pred == ICmpInst::Predicate::ICMP_NE)
2808     std::swap(X, XBiasedHighBits);
2809 
2810   // FIXME: we could support non non-splats here.
2811 
2812   const APInt *LowBitMaskCst;
2813   if (!match(XLowBits, m_And(m_Specific(X), m_APIntAllowUndef(LowBitMaskCst))))
2814     return nullptr;
2815 
2816   // Match even if the AND and ADD are swapped.
2817   const APInt *BiasCst, *HighBitMaskCst;
2818   if (!match(XBiasedHighBits,
2819              m_And(m_Add(m_Specific(X), m_APIntAllowUndef(BiasCst)),
2820                    m_APIntAllowUndef(HighBitMaskCst))) &&
2821       !match(XBiasedHighBits,
2822              m_Add(m_And(m_Specific(X), m_APIntAllowUndef(HighBitMaskCst)),
2823                    m_APIntAllowUndef(BiasCst))))
2824     return nullptr;
2825 
2826   if (!LowBitMaskCst->isMask())
2827     return nullptr;
2828 
2829   APInt InvertedLowBitMaskCst = ~*LowBitMaskCst;
